1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  priorContracts: number;
4	  firstInsurance?: boolean;
5	};
6	
7	export type Item = Record<string, unknown>;
8	
9	export type Policy = {
10	  customer: Customer;
11	  items: Item[];
12	};
13	
14	export type QuoteResult = {
15	  premium: number;
16	};
17	
18	export type ClaimResult = {
19	  payout: number;
20	  remainingCap: number;
21	};
22	
23	const PROCESSING_FEE = 5;
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	
28	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  component: COMPONENT_BASE_PREMIUM,
34	};
35	
36	const basePremiumForItem = (item: Item): number => {
37	  const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type as string];
38	  if (base === undefined) {
39	    throw new Error(`Unknown item type: ${String(item.type)}`);
40	  }
41	  return base;
42	};
43	
44	const isComponent = (item: Item): boolean => item.type === "component";
45	
46	const groupComponentsByType = (items: Item[]): Map<string, number> => {
47	  const groups = new Map<string, number>();
48	  for (const item of items.filter(isComponent)) {
49	    const key = item.componentType as string;
50	    groups.set(key, (groups.get(key) ?? 0) + 1);
51	  }
52	  return groups;
53	};
54	
55	const componentGroupPremium = (count: number): number =>
56	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_BASE_PREMIUM;
57	
58	const componentsPremium = (items: Item[]): number =>
59	  Array.from(groupComponentsByType(items).values()).reduce(
60	    (sum, count) => sum + componentGroupPremium(count),
61	    0,
62	  );
63	
64	const CURSE_SURCHARGE_RATE = 0.5;
65	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
66	const HIGH_ENCHANTMENT_THRESHOLD = 5;
67	
68	type ItemModifier = (item: Item, base: number) => number;
69	
70	const curseModifier: ItemModifier = (item, base) =>
71	  item.cursed === true ? base * CURSE_SURCHARGE_RATE : 0;
72	
73	const highEnchantmentModifier: ItemModifier = (item, base) =>
74	  (item.enchantment as number) >= HIGH_ENCHANTMENT_THRESHOLD
75	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
76	    : 0;
77	
78	const ITEM_MODIFIERS: ItemModifier[] = [curseModifier, highEnchantmentModifier];
79	
80	const itemPremium = (item: Item): number => {
81	  const base = basePremiumForItem(item);
82	  return ITEM_MODIFIERS.reduce(
83	    (premium, modifier) => premium + modifier(item, base),
84	    base,
85	  );
86	};
87	
88	type NonComponentTotals = { base: number; withModifiers: number };
89	
90	const nonComponentsTotals = (items: Item[]): NonComponentTotals =>
91	  items
92	    .filter((item) => !isComponent(item))
93	    .reduce<NonComponentTotals>(
94	      (totals, item) => ({
95	        base: totals.base + basePremiumForItem(item),
96	        withModifiers: totals.withModifiers + itemPremium(item),
97	      }),
98	      { base: 0, withModifiers: 0 },
99	    );
100	
101	const LOYALTY_DISCOUNT_RATE = 0.2;
102	const LOYALTY_YEARS_THRESHOLD = 2;
103	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
104	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
105	const FOLLOW_UP_PRIOR_CONTRACTS_THRESHOLD = 1;
106	
107	type PolicyAdjustment = (customer: Customer, basePremium: number) => number;
108	
109	const loyaltyAdjustment: PolicyAdjustment = (customer, basePremium) =>
110	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
111	    ? -basePremium * LOYALTY_DISCOUNT_RATE
112	    : 0;
113	
114	const firstInsuranceAdjustment: PolicyAdjustment = (customer, basePremium) =>
115	  customer.firstInsurance === true ? basePremium * FIRST_INSURANCE_SURCHARGE_RATE : 0;
116	
117	const followUpAdjustment: PolicyAdjustment = (customer, basePremium) =>
118	  customer.priorContracts >= FOLLOW_UP_PRIOR_CONTRACTS_THRESHOLD
119	    ? -basePremium * FOLLOW_UP_DISCOUNT_RATE
120	    : 0;
121	
122	const POLICY_ADJUSTMENTS: PolicyAdjustment[] = [
123	  loyaltyAdjustment,
124	  firstInsuranceAdjustment,
125	  followUpAdjustment,
126	];
127	
128	const totalPolicyAdjustment = (customer: Customer, basePremium: number): number =>
129	  POLICY_ADJUSTMENTS.reduce(
130	    (sum, adjustment) => sum + adjustment(customer, basePremium),
131	    0,
132	  );
133	
134	export function quote(policy: Policy): QuoteResult {
135	  const componentsTotal = componentsPremium(policy.items);
136	  const nonComponents = nonComponentsTotals(policy.items);
137	  const itemsTotal = nonComponents.withModifiers + componentsTotal;
138	  const policyBase = nonComponents.base + componentsTotal;
139	  return {
140	    premium: Math.ceil(itemsTotal + totalPolicyAdjustment(policy.customer, policyBase) + PROCESSING_FEE),
141	  };
142	}
143	
144	export type Damage = {
145	  itemType: string;
146	  amount: number;
147	  componentType?: string;
148	};
149	
150	export type ClaimEvent = {
151	  cause: string;
152	  damages: Damage[];
153	};
154	
155	const DEDUCTIBLE_PER_DAMAGE = 100;
156	
157	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
158	  sword: 1000,
159	  amulet: 600,
160	  staff: 800,
161	  potion: 400,
162	  component: 250,
163	};
164	
165	const insuranceValueForItem = (item: Item): number =>
166	  INSURANCE_VALUE_BY_ITEM_TYPE[item.type as string] ?? 0;
167	
168	const CAP_MULTIPLIER = 2;
169	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
170	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
171	
172	const findPolicyItem = (items: Item[], itemType: string): Item | undefined =>
173	  items.find((item) => item.type === itemType);
174	
175	const reimbursementBeforeDeductible = (damage: Damage, item: Item | undefined): number => {
176	  if (item && (item.enchantment as number) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
177	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
178	  }
179	  return damage.amount;
180	};
181	
182	const damagePayout = (damage: Damage, items: Item[]): number => {
183	  const item = findPolicyItem(items, damage.itemType);
184	  return reimbursementBeforeDeductible(damage, item) - DEDUCTIBLE_PER_DAMAGE;
185	};
186	
187	const totalInsuranceValue = (items: Item[]): number =>
188	  items.reduce((sum, item) => sum + insuranceValueForItem(item), 0);
189	
190	const initialCapFor = (items: Item[]): number =>
191	  CAP_MULTIPLIER * totalInsuranceValue(items);
192	
193	const damageKey = (damage: Damage): string =>
194	  damage.itemType === "component"
195	    ? `component:${damage.componentType as string}`
196	    : damage.itemType;
197	
198	const itemKey = (item: Item): string =>
199	  item.type === "component"
200	    ? `component:${item.componentType as string}`
201	    : (item.type as string);
202	
203	const countByKey = <T>(values: T[], keyFn: (value: T) => string): Map<string, number> => {
204	  const counts = new Map<string, number>();
205	  for (const value of values) {
206	    const key = keyFn(value);
207	    counts.set(key, (counts.get(key) ?? 0) + 1);
208	  }
209	  return counts;
210	};
211	
212	const validateDamageAmounts = (damages: Damage[]): void => {
213	  for (const damage of damages) {
214	    if (damage.amount < 0) {
215	      throw new Error("Damage amount must be non-negative");
216	    }
217	  }
218	};
219	
220	const validateDamageCounts = (items: Item[], damages: Damage[]): void => {
221	  const itemCounts = countByKey(items, itemKey);
222	  const damageCounts = countByKey(damages, damageKey);
223	  for (const [key, count] of damageCounts) {
224	    if (count > (itemCounts.get(key) ?? 0)) {
225	      throw new Error(`More damages of type ${key} than insured`);
226	    }
227	  }
228	};
229	
230	const validateDamages = (items: Item[], damages: Damage[]): void => {
231	  validateDamageAmounts(damages);
232	  validateDamageCounts(items, damages);
233	};
234	
235	export function claim(policy: { items: Item[]; remainingCap?: number }, event: ClaimEvent): ClaimResult {
236	  validateDamages(policy.items, event.damages);
237	  const uncappedPayout = event.damages.reduce(
238	    (sum, damage) => sum + damagePayout(damage, policy.items),
239	    0,
240	  );
241	  const cap = policy.remainingCap ?? initialCapFor(policy.items);
242	  const cappedPayout = Math.min(uncappedPayout, cap);
243	  const payout = Math.floor(cappedPayout);
244	  return { payout, remainingCap: cap - payout };
245	}
